"use client";

import { useState } from "react";
import { X, Trash2, Plus, Minus, CreditCard, ShoppingCart, List } from "lucide-react";

export default function CartSidebar({ isCartOpen, onClose, cartItems, setCartItems }) {
    const [activeTab, setActiveTab] = useState("shopcart");

    const total = cartItems.reduce((acc, item) => acc + item.price * item.qty, 0);

    const increaseQty = (id) => {
        setCartItems(prev =>
            prev.map(item => {
                if (item.id === id) {
                    if (item.qty + 1 > item.stock) {
                        return { ...item, warning: true };
                    }
                    return { ...item, qty: item.qty + 1, warning: false };
                }
                return item;
            })
        );
    };

    const decreaseQty = (id) => {
        setCartItems(prev =>
            prev.map(item => {
                if (item.id === id) {
                    const newQty = Math.max(item.qty - 1, 1);
                    return { ...item, qty: newQty, warning: false };
                }
                return item;
            })
        );
    };

    const removeItem = (id) => {
        setCartItems(prev => prev.filter(item => item.id !== id));
    };

    return (
        <>
            {isCartOpen && <div className="fixed inset-0 bg-black/30 z-40" onClick={onClose} />}
            <div
                className={`fixed top-0 right-0 w-96 h-full bg-white shadow-lg z-50 transform transition-transform duration-300 flex flex-col ${
                    isCartOpen ? "translate-x-0" : "translate-x-full"
                }`}
            >
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b">
                    <h2 className="text-lg font-semibold">Shop cart</h2>
                    <button onClick={onClose}><X size={24} /></button>
                </div>

                {/* Tabs */}
                <div className="flex items-center gap-2 px-6 py-2 border-b text-sm">
                    <button
                        onClick={() => setActiveTab("shopcart")}
                        className={`flex items-center space-x-1 ${activeTab === "shopcart" ? "text-green-600 font-medium" : "text-gray-500"}`}
                    >
                        <ShoppingCart size={16} />
                        <span>ShopCart</span>
                    </button>
                    <span>/</span>
                    <button
                        onClick={() => setActiveTab("order")}
                        className={`flex items-center space-x-1 ${activeTab === "order" ? "text-green-600 font-medium" : "text-gray-500"}`}
                    >
                        <List size={16} />
                        <span>Order</span>
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 p-6 space-y-6 overflow-y-auto">
                    {activeTab === "shopcart" &&
                        cartItems.map(item => (
                            <div key={item.id} className="flex flex-col space-y-1 pb-4 border-b">
                                <div className="flex items-start space-x-4">
                                    <img src={item.image} alt={item.name} className="w-16 h-16 border rounded object-cover" />
                                    <div className="flex-1">
                                        <p className="text-sm font-medium">{item.name}</p>
                                        <p className="text-xs text-gray-500">In stock: {item.stock}</p>
                                        <button onClick={() => removeItem(item.id)} className="text-red-500 text-xs flex items-center mt-1">
                                            <Trash2 size={12} className="mr-1" /> Remove
                                        </button>
                                    </div>
                                    <div className="flex flex-col items-end justify-between">
                                        <div className="flex items-center border rounded">
                                            <button onClick={() => decreaseQty(item.id)} className="px-2 py-1 hover:bg-gray-100"><Minus size={14} /></button>
                                            <span className="px-3">{item.qty}</span>
                                            <button onClick={() => increaseQty(item.id)} className="px-2 py-1 hover:bg-gray-100"><Plus size={14} /></button>
                                        </div>
                                        <span className="mt-2 font-semibold">฿{item.price * item.qty}</span>
                                    </div>
                                </div>
                                {item.warning && <div className="text-red-600 text-xs font-medium">⚠️ Quantity exceeds stock!</div>}
                            </div>
                        ))}

                    {activeTab === "order" && <div className="text-gray-500 text-sm">📦 Your order history will appear here...</div>}
                </div>

                {/* Footer */}
                {activeTab === "shopcart" && (
                    <div className="p-4 border-t bg-white">
                        <button className="w-full flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700 text-white py-3 rounded-lg text-base font-medium">
                            <CreditCard size={18} />
                            Payment ฿{total}
                        </button>
                    </div>
                )}
            </div>
        </>
    );
}
